import time
import functools

def timer(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        baslangic = time.perf_counter()
        sonuc = func(*args, **kwargs)
        gecen = time.perf_counter() - baslangic
        print(f"Fonksiyon {func.__name__} {gecen:.4f} saniye surdu")
        return sonuc
    return wrapper

@timer
def hesapla(n):
    toplam = 0
    for i in range(n):
        toplam += i ** 2
    return toplam

print(hesapla(10_000_000))

class DosyaYoneticisi:
    def __init__(self, dosya_adi, mod):
        self.dosya_adi = dosya_adi
        self.mod = mod
        self.dosya = None

    def __enter__(self):
        self.dosya = open(self.dosya_adi, self.mod, encoding='utf-8')
        return self.dosya

    def __exit__(self, exc_type, exc_val, exc_tb):
        if self.dosya:
            self.dosya.close()
        if exc_type is not None:
            print(f"Hata olustu: {exc_type.__name__}")
            return True
        return False

