class OzelListe:
    def __init__(self, elemanlar):
        self.elemanlar = list(elemanlar)

    def __str__(self):
        return f"OzelListe({self.elemanlar})"

    def __repr__(self):
        return f"OzelListe({self.elemanlar!r})"

    def __len__(self):
        return len(self.elemanlar)

    def __getitem__(self, index):
        if isinstance(index, slice):
            return OzelListe(self.elemanlar[index])
        return self.elemanlar[index]

    def __add__(self, other):
        if isinstance(other, OzelListe):
            return OzelListe(self.elemanlar + other.elemanlar)
        return NotImplemented

