import java.util.concurrent.*;
import java.util.stream.*;
public class Main {
    public static void main(String[] args) throws Exception {
        CompletableFuture<Integer> s1 = CompletableFuture.supplyAsync(()->{ sleep(1000); return 250; });
        CompletableFuture<Integer> s2 = CompletableFuture.supplyAsync(()->{ sleep(1500); return 180; });
        CompletableFuture<Integer> s3 = CompletableFuture.supplyAsync(()->{ sleep(800); return 320; });
        CompletableFuture<Integer> t = CompletableFuture.allOf(s1,s2,s3)
            .thenApply(v->Stream.of(s1,s2,s3).map(CompletableFuture::join).mapToInt(Integer::intValue).sum());
        System.out.println("Toplam: "+t.get());
        CompletableFuture<String> h = CompletableFuture.supplyAsync(()->{ if(Math.random()>0.5) throw new RuntimeException("Hata"); return "OK"; })
            .exceptionally(e->"Hata: "+e.getMessage()).thenApply(x->"Sonuc: "+x);
        System.out.println(h.get());
        CompletableFuture<String> z = CompletableFuture.supplyAsync(()->"K-42").thenCompose(id->CompletableFuture.supplyAsync(()->id+" yuklendi"));
        System.out.println(z.get());
    }
    static void sleep(int m) { try { Thread.sleep(m); } catch(InterruptedException e){} }
}

