type CrudEndpoints<T extends string> = {
    [K in T as `${Capitalize<K>}GetRequest`]: { id: number };
    [K in T as `${Capitalize<K>}GetResponse`]: Record<string, unknown>;
    [K in T as `${Capitalize<K>}PostRequest`]: Record<string, unknown>;
    [K in T as `${Capitalize<K>}PostResponse`]: { id: number };
    [K in T as `${Capitalize<K>}PutRequest`]: { id: number } & Record<string, unknown>;
    [K in T as `${Capitalize<K>}PutResponse`]: { success: boolean };
    [K in T as `${Capitalize<K>}DeleteRequest`]: { id: number };
    [K in T as `${Capitalize<K>}DeleteResponse`]: { success: boolean };
};
type EntityEvents<T extends string> = {
    [K in T as `${Capitalize<K>}Created`]: { entityId: number; timestamp: Date };
    [K in T as `${Capitalize<K>}Updated`]: { entityId: number; degisenAlanlar: string[]; timestamp: Date };
    [K in T as `${Capitalize<K>}Deleted`]: { entityId: number; timestamp: Date };
};
type FullApi<T extends string> = CrudEndpoints<T> & EntityEvents<T>;
