package main
import (
	"fmt"
	"sync"
	"time"
)
type Job struct { ID int; Data int }
type Result struct { JobID int; Output int; WorkerID int }
func worker(id int, jobs <-chan Job, results chan<- Result, wg *sync.WaitGroup) {
	defer wg.Done()
	for job := range jobs {
		time.Sleep(time.Millisecond * time.Duration(100+job.Data%50))
		results <- Result{job.ID, job.Data * 2, id}
	}
}
func main() {
	const nw, nj = 5, 20
	jobs := make(chan Job, nj)
	results := make(chan Result, nj)
	var wg sync.WaitGroup
	for i := 1; i <= nw; i++ { wg.Add(1); go worker(i, jobs, results, &wg) }
	for i := 1; i <= nj; i++ { jobs <- Job{i, i * 10} }
	close(jobs)
	go func() { wg.Wait(); close(results) }()
	for r := range results { fmt.Printf("Isci %d -> Job %d: %d\n", r.WorkerID, r.JobID, r.Output) }
}

