)
type Counter struct { mu sync.Mutex; val int }
func (c *Counter) Inc() { c.mu.Lock(); defer c.mu.Unlock(); c.val++ }
func (c *Counter) Dec() { c.mu.Lock(); defer c.mu.Unlock(); c.val-- }
func (c *Counter) Val() int { c.mu.Lock(); defer c.mu.Unlock(); return c.val }
type Cache struct { mu sync.RWMutex; data map[string]string }
func (c *Cache) Get(k string) string { c.mu.RLock(); defer c.mu.RUnlock(); return c.data[k] }
func (c *Cache) Set(k, v string) { c.mu.Lock(); defer c.mu.Unlock(); if c.data==nil {c.data=make(map[string]string)}; c.data[k]=v }
func main() {
	var cnt Counter; var wg sync.WaitGroup
	for i:=0;i<1000;i++{wg.Add(1);go func(){defer wg.Done();cnt.Inc()}()}
	wg.Wait(); fmt.Printf("Counter: %d\n", cnt.Val())
	cache:=Cache{data:make(map[string]string)}
	for i:=0;i<100;i++{wg.Add(1);go func(i int){defer wg.Done();k:=fmt.Sprintf("k-%d",i);cache.Set(k,"v")}(i)}
	wg.Wait(); fmt.Println("Cache OK")
}

