  public static void sirala(int[] dizi) {
    int adet = dizi.length;
    for (int index = 0; index < adet - 1; index++) {
      for (int index2 = 0; index2 < adet - index - 1; index2++) {
        if (dizi[index2] > dizi[index2 + 1]) {
          int gecici = dizi[index2];
          dizi[index2] = dizi[index2 + 1];
          dizi[index2 + 1] = gecici;
        }
      }
    }
  }

  public static void main(String[] args) {
    int[] sayilar = {64, 34, 25, 12, 22};
    sirala(sayilar);
    System.out.print("Sirali dizi: ");
    for (int index = 0; index < sayilar.length; index++) {
      System.out.print(sayilar[index] + " ");
    }
  }
}

