let deneme = 0;
let oyunBitti = false;

function tahminEt() {
    if (oyunBitti) {
        document.getElementById('sonuc').textContent = 'Oyun bitti. Sayfayi yenileyin!';
        return;
    }
    const tahmin = parseInt(document.getElementById('tahmin').value);
    if (isNaN(tahmin) || tahmin < 1 || tahmin > 100) {
        document.getElementById('sonuc').textContent = '1-100 arasi bir sayi girin!';
        return;
    }
    deneme++;
    let mesaj;
    if (tahmin < hedef) {
        mesaj = 'Daha buyuk bir sayi girin';
    } else if (tahmin > hedef) {
        mesaj = 'Daha kucuk bir sayi girin';
    } else {
        mesaj = `Tebrikler! ${deneme} denemede buldunuz.`;
        oyunBitti = true;
    }
    document.getElementById('sonuc').textContent = mesaj;
    document.getElementById('deneme').textContent = `Deneme: ${deneme}`;
}

function sifreUret() {
    const uzunluk = parseInt(document.getElementById('uzunluk').value) || 8;
    if (uzunluk < 4) {
        document.getElementById('sifre').textContent = 'Uzunluk en az 4 olmali';
        return;
    }
    const kucuk = 'abcdefghijklmnopqrstuvwxyz';
    const buyuk = kucuk.toUpperCase();
    const rakam = '0123456789';
    const sembol = '!@#$%^&*()_+-=[]{}|;:,.<>?';
    const tum = kucuk + buyuk + rakam + sembol;

    let sifre = '';
    sifre += kucuk[Math.floor(Math.random() * kucuk.length)];
    sifre += buyuk[Math.floor(Math.random() * buyuk.length)];
    sifre += rakam[Math.floor(Math.random() * rakam.length)];
    sifre += sembol[Math.floor(Math.random() * sembol.length)];

    for (let i = 4; i < uzunluk; i++) {
        sifre += tum[Math.floor(Math.random() * tum.length)];
    }
    sifre = sifre.split('').sort(() => Math.random() - 0.5).join('');
    document.getElementById('sifre').textContent = sifre;
    document.getElementById('sifre').style.fontFamily = 'monospace';
}

function kopyala() {
    const sifre = document.getElementById('sifre').textContent;
    navigator.clipboard.writeText(sifre);
    alert('Sifre kopyalandi!');
}

