	return HavaDurumu{
		Sehir:    sehir,
		Sicaklik: rand.Intn(35) - 5,
		Durum:    durumlar[rand.Intn(len(durumlar))],
		Nem:      rand.Intn(60) + 30,
	}
}

func main() {
	rand.Seed(time.Now().UnixNano())
	sehirler := []string{"Istanbul", "Ankara", "Izmir", "Antalya", "Bursa"}

	for _, sehir := range sehirler {
		h := havaDurumuGetir(sehir)
		fmt.Printf("%s: %d derece, %s, Nem: %d%%\n",
			h.Sehir, h.Sicaklik, h.Durum, h.Nem)
	}
}

