interface Urun {
  isim: string;
  fiyat: number;
  miktar: number;
}

function urunFiltrele(urunler: Urun[], minFiyat: number, maxFiyat: number): Urun[] {
  return urunler.filter(function(urun) {
    return urun.fiyat >= minFiyat && urun.fiyat <= maxFiyat;
  });
}

