function enUzunKelimeBul(kelimeler: string[]): string {
  let enUzun: string = kelimeler[0];
  for (let index = 1; index < kelimeler.length; index++) {
    if (kelimeler[index].length > enUzun.length) {
      enUzun = kelimeler[index];
    }
  }
  return enUzun;
}

